import javax.swing.*;

public class JLabelExample {
 public static void main(String[] args) {
 JFrame frame = new JFrame("JLabel Example");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 frame.setSize(300, 200);

 // Create a JLabel with text
 JLabel textLabel = new JLabel("Welcome to Advanced Java!", SwingConstants.CENTER);

 // Create a JLabel with icon
 ImageIcon icon = new ImageIcon("path/to/icon.png");
 JLabel iconLabel = new JLabel(icon);

 // Add labels to frame
 frame.add(textLabel, BorderLayout.NORTH);
 frame.add(iconLabel, BorderLayout.CENTER);

 frame.setVisible(true);
 }
}

import javax.swing.*;

public class SetIconExample {
 public static void main(String[] args) {
 JFrame frame = new JFrame("Set Icon Example");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 frame.setSize(300, 200);

 // Create a JLabel with text
 JLabel label = new JLabel("Hello World!");

 // Load ImageIcon
 ImageIcon icon = new ImageIcon("path/to/icon.png");

 // Set icon for JLabel
 label.setIcon(icon);

 // Add label to frame
 frame.add(label);

 frame.setVisible(true);
 }
}
